with open(data_file, 'r', encoding='utf-8') as f:
    data = json.load(f)

for hero_key, hero_data in data.items():
    hero_id = hero_data.get('hero_id')
    if hero_id in new_strategies and 'strategy' in hero_data:
        # Delete playstyle if it exists
        if 'playstyle' in hero_data['strategy']:
            del hero_data['strategy']['playstyle']
            
        # Add the 5 new properties
        props = new_strategies[hero_id]
        hero_data['strategy']['earlyGame'] = props['earlyGame']
        hero_data['strategy']['midGame'] = props['midGame']
        hero_data['strategy']['lateGame'] = props['lateGame']
        hero_data['strategy']['teamfight'] = props['teamfight']
        hero_data['strategy']['commonMistakes'] = props['commonMistakes']

with open(output_file, 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print(f"Successfully processed {len(new_strategies)} heroes and saved to {output_file}")
